69	table.dt th{padding:3px 8px;background:#f7f7f7;color:#888;font-weight:500;text-align:right;border-bottom:0.5px solid #e0e0e0;white-space:nowrap;font-size:10px}
70	table.dt th:first-child{text-align:left}
