80	@media print{
81	  /* ===== ページ設定 ===== */
82	  @page{size:A4 portrait;margin:18mm 18mm 18mm 18mm}
83	  html,body{margin:0!important;padding:0!important;width:100%!important}
84	  body>.app{display:none!important}
85	  #pdf-report{display:block!important}
86	
87	  /* ===== レポート基本 ===== */
88	  #pdf-report{
89	    font-family:Arial,Helvetica,sans-serif;
90	    font-size:9pt;color:#222;line-height:1.5;
91	    width:100%;box-sizing:border-box;
92	    padding:0;margin:0;
93	  }
94	  /* sub/supをレイアウトに影響させない */
95	  #pdf-report sub,#pdf-report sup{
96	    font-size:70%;line-height:0;position:relative;vertical-align:baseline
97	  }
98	  #pdf-report sup{top:-0.4em}
99	  #pdf-report sub{bottom:-0.2em}
100	
101	  /* ===== ヘッダー ===== */
102	  .rpt-title{font-size:15pt;font-weight:700;color:#185FA5;margin:0 0 2pt;padding:0}
103	  .rpt-sub{font-size:8pt;color:#888;border-bottom:1.5pt solid #185FA5;padding-bottom:5pt;margin-bottom:10pt}
104	
105	  /* ===== セクション ===== */
106	  .rpt-sec{
107	    font-size:10pt;font-weight:700;color:#185FA5;
108	    border-left:3pt solid #185FA5;padding-left:7pt;
109	    margin:12pt 0 5pt;page-break-after:avoid
110	  }
111	  .rpt-block{page-break-inside:avoid;margin-bottom:8pt}
112	
113	  /* ===== 解析条件テーブル ===== */
114	  .rpt-tbl{
115	    width:100%;border-collapse:collapse;
116	    font-size:8.5pt;table-layout:fixed;
117	    border:1pt solid #ccc
118	  }
119	  .rpt-tbl col.c1{width:40%}.rpt-tbl col.c2{width:60%}
120	  .rpt-tbl td{
121	    padding:3pt 7pt;
122	    border:1pt solid #ddd;
123	    word-break:break-word;vertical-align:top;
124	    box-sizing:border-box;overflow:hidden
125	  }
126	  .rpt-tbl tr:nth-child(odd) td{background:#f7f7f7}
127	  .rpt-tbl td:first-child{color:#444;font-weight:500}
128	
129	  /* ===== 結果カード ===== */
130	  .rpt-cards{
131	    width:100%;border-collapse:collapse;
132	    font-size:8.5pt;table-layout:fixed;
133	    border:1pt solid #ccc;margin-bottom:6pt
134	  }
135	  .rpt-cards td{
136	    width:33.33%;padding:5pt 7pt;
137	    border:1pt solid #ddd;
138	    background:#f5f5f3;vertical-align:top;
139	    box-sizing:border-box;overflow:hidden
140	  }
141	  .rpt-cards .cl{font-size:7.5pt;color:#888;display:block;margin-bottom:1pt}
142	  .rpt-cards .cv{font-size:11pt;font-weight:600;display:block;word-break:break-all}
143	
144	  /* ===== アラート ===== */
145	  .rpt-alert{padding:5pt 8pt;font-size:8.5pt;margin-bottom:6pt;border-left:3pt solid}
146	  .rpt-alert-ok{background:#EAF3DE;color:#27500A;border-color:#639922}
147	  .rpt-alert-dn{background:#FCEBEB;color:#791F1F;border-color:#E24B4A}
148	
149	  /* ===== グラフ画像 ===== */
150	  .rpt-charts{width:100%;border-collapse:collapse;table-layout:fixed}
151	  .rpt-charts td{padding:0 3pt;vertical-align:top;box-sizing:border-box}
152	  .rpt-charts img{width:100%;height:auto;display:block}
153	
154	  /* ===== 破損解析テーブル ===== */
155	  .rpt-fail{
156	    width:100%;border-collapse:collapse;
157	    font-size:8.5pt;table-layout:fixed;
158	    border:1pt solid #ccc
159	  }
160	  .rpt-fail col.f1{width:44%}
161	  .rpt-fail col.f2{width:20%}
162	  .rpt-fail col.f3{width:18%}
163	  .rpt-fail col.f4{width:18%}
164	  .rpt-fail th{
165	    background:#f0f0f0;padding:3pt 7pt;
166	    font-weight:600;color:#444;
167	    border:1pt solid #ccc;font-size:8pt;text-align:left
168	  }
169	  .rpt-fail th.num,.rpt-fail td.num{text-align:right;font-variant-numeric:tabular-nums}
170	  .rpt-fail td{padding:3pt 7pt;border:1pt solid #ddd;box-sizing:border-box;overflow:hidden}
171	  .rpt-fail tr:nth-child(even) td{background:#fafafa}
172	  .rpt-fail .ctrl{color:#A32D2D;font-weight:600}
173	
174	  /* ===== 継手解析テーブル ===== */
175	  .rpt-jt{
176	    width:100%;border-collapse:collapse;
177	    font-size:8.5pt;table-layout:fixed;
178	    border:1pt solid #ccc
179	  }
180	  .rpt-jt col.j1{width:38%}
181	  .rpt-jt col.j2{width:22%}
182	  .rpt-jt col.j3{width:40%}
183	  .rpt-jt td{
184	    padding:3pt 7pt;border:1pt solid #ddd;
185	    word-break:break-word;vertical-align:top;
186	    box-sizing:border-box;overflow:hidden
187	  }
188	  .rpt-jt tr:nth-child(odd) td{background:#f7f7f7}
189	  .rpt-jt td:first-child{color:#444;font-weight:500}
190	  .rpt-jt td.num{text-align:right}
191	  .rpt-jt td.note{color:#666;font-size:8pt}
192	
193	  /* ===== フッター ===== */
194	  .rpt-foot{
195	    font-size:7.5pt;color:#aaa;text-align:center;
196	    border-top:1pt solid #ddd;padding-top:6pt;margin-top:12pt
197	  }
198	
199	  /* ===== 色印刷強制 ===== */

550	function doCalc(d,grK,Lg,mt,mw,nutK,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns){
551	  const b=BOLT[d],gr=GRADE[grK],nut=NUT_MAT[nutK],Eb=gr.E;
552	  const half=ang/2*Math.PI/180,beta=Math.atan(b.p/(Math.PI*b.d2)),rho=Math.atan(mt/Math.cos(half));
553	  let dw=b.dw,muw=mw;
554	  if(was==='flat')dw*=1.5;if(was==='spring')muw*=0.9;
555	  const bArea=(Math.PI/4)*(dw*dw-b.dh*b.dh),le=dep*d,nTh=le/b.p;
556	  const Fbrk=gr.Su*b.As/1000*tmp,Fstr=nut.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000,FbA=bA*bArea/1000,FbB=bB*bArea/1000,Fyld=gr.Sy*b.As/1000*tmp;
557	  const Flim=Math.min(Fbrk,Fstr,FbA,FbB);
558	  const failMode=[{mode:'ボルト破断',F:Fbrk},{mode:'山飛び（めねじ）',F:Fstr},{mode:'座面陥没 A面',F:FbA},{mode:'座面陥没 B面',F:FbB}].reduce((a,x)=>x.F<a.F?x:a).mode;
559	  const denom=(b.d2/2)*Math.tan(beta+rho)+(dw/2)*muw,Test=Flim*denom*1.35,step=Test/ns;
560	  const rows=[];
561	  for(let i=0;i<=ns+30;i++){
562	    const T=i*step,Fe=T/denom,sig=Fe*1000/b.As,J=Math.PI*Math.pow(b.d3/2,4)/2,tau=T*1000*(b.d3/2)/J*0.5,seq=Math.sqrt(sig*sig+3*tau*tau),plastic=seq>gr.Sy*tmp,Fact=plastic?Math.min(Fe,Fyld*1.01):Fe,util=seq/(gr.Su*tmp)*100;
563	    rows.push({T:+T.toFixed(3),F:+(Fact/1000).toFixed(4),sig:+sig.toFixed(1),tau:+tau.toFixed(1),seq:+seq.toFixed(1),util:+util.toFixed(1),plastic,over:Fact/1000>=Flim/1000*0.998});
564	    if(Fact/1000>Flim/1000*1.02)break;
565	  }
566	  return{rows,Flim,Fbrk,Fstr,FbA,FbB,Fyld,T_lim:rows.find(r=>r.over)?.T||null,T_yld:rows.find(r=>r.plastic)?.T||null,failMode,b,gr,nut,nutK,grK,d,dep,mu_t:mt,mu_w:muw,denom,dw,stiff:calcStiff(b,Eb,Lg,cmA,cmB,tA,tB),Eb,Lg,cmA,cmB,tA,tB,bA,bB};
567	}
568	function calc(){
569	  const ns=200,d=+gv('diam'),gr=gv('grade'),Lg=+gv('bolt_lg'),mt=+gv('mu_t'),mw=+gv('mu_w'),nut=gv('nut_mat'),dep=+gv('depth'),ang=+gv('thread_angle'),was=gv('washer'),tmp=+gv('temp'),bA=+gv('bearing_a'),bB=+gv('bearing_b'),cmA=gv('clamped_mat_a'),cmB=gv('clamped_mat_b'),tA=+gv('thick_a'),tB=+gv('thick_b');
570	  RES=doCalc(d,gr,Lg,mt,mw,nut,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns);
571	  const cmp=ge('cmp_on').checked;
572	  RES2=cmp?doCalc(+gv('diam2'),gv('grade2'),Lg,0.13,0.13,gv('nut_mat2'),+gv('depth2'),60,'none',tmp,bA,bB,gv('clamped_mat_a2'),gv('clamped_mat_b2'),+gv('thick_a2'),+gv('thick_b2'),ns):null;
573	  const sf=+gv('safety'),fext=+gv('f_ext');
574	  updateTop(RES,sf,cmp);
575	  if(curTab==='graph')drawGraphs(RES,RES2,sf);
576	  else if(curTab==='table')buildTable(RES);
577	  else if(curTab==='breakdown')buildBreakdown(RES,sf);
578	  else buildJoint(RES,sf,fext);
579	}
580	function updateTop(r,sf,cmp){
581	  ge('v-flim').innerHTML=(r.Flim/1000).toFixed(2)+'<span class="mc-u">kN</span>';
582	  ge('v-tlim').innerHTML=(r.T_lim?r.T_lim.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
583	  ge('v-tyld').innerHTML=(r.T_yld?r.T_yld.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
584	  ge('v-trec').innerHTML=(r.T_lim?(r.T_lim/sf).toFixed(1):'—')+'<span class="mc-u">Nm</span>';
585	  ge('v-trec-s').textContent='安全率 '+sf.toFixed(1);
586	  ge('v-phi').innerHTML=r.stiff.phi.toFixed(3);
587	  ge('mc0').className='mc '+(r.failMode!=='ボルト破断'?'danger':'ok');
588	  ge('bdg-mode').textContent=cmp?'比較モード':'単一解析';ge('bdg-mode').className='badge '+(cmp?'b-am':'b-bl');
589	  ge('bdg-fail').textContent=r.failMode==='ボルト破断'?'正常':'警告: '+r.failMode;ge('bdg-fail').className='badge '+(r.failMode==='ボルト破断'?'b-gn':'b-rd');
590	  const alerts=[];
591	  if(r.failMode==='山飛び（めねじ）')alerts.push('<div class="alert al-dn"><strong>警告: 山飛びリスク</strong>　めねじせん断破壊がボルト破断より先に発生します。ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。</div>');
592	  else if(r.failMode.includes('座面'))alerts.push(`<div class="alert al-dn"><strong>警告: 座面陥没リスク（${r.failMode}）</strong>　面圧超過がボルト破断より先に発生します。ワッシャー使用または許容面圧を見直してください。</div>`);
593	  if(r.stiff.phi>0.3)alerts.push(`<div class="alert al-wn">剛性比 Φ=${r.stiff.phi.toFixed(3)} — ボルト剛性が高く外部軸力がボルトに伝わりやすい状態です。</div>`);
594	  else if(r.stiff.phi<0.1)alerts.push(`<div class="alert al-ok">剛性比 Φ=${r.stiff.phi.toFixed(3)} — 部材剛性が高く外部軸力による軸力変動が小さい良好な継手です。</div>`);
595	  ge('alert-area').innerHTML=alerts.join('')||'<div class="alert al-ok">設計は良好です。ボルト破断が支配的で延性破壊が先行します。</div>';
596	}
597	function mkC(id,cfg){if(CH[id])CH[id].destroy();CH[id]=new Chart(ge(id).getContext('2d'),cfg)}
598	function drawGraphs(A,B,sf){
599	  const wc=A.failMode!=='ボルト破断',lc=wc?'#E24B4A':'#185FA5';
600	  const ds=[
601	    {label:'弾性域(A)',data:A.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
602	    {label:'塑性域(A)',data:A.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#EF9F27',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
603	    {label:'限界域(A)',data:A.rows.filter(r=>r.over).map(r=>({x:r.T,y:r.F})),borderColor:lc,backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,3]}
604	  ];
605	  if(B){ds.push({label:'弾性域(B)',data:B.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#D85A30',backgroundColor:'transparent',borderWidth:2,pointRadius:0,tension:0.2,borderDash:[4,2]});ds.push({label:'塑性域(B)',data:B.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#993C1D',backgroundColor:'transparent',borderWidth:2,pointRadius:0,tension:0.2,borderDash:[4,2]});}
606	  if(A.T_lim){const rt=A.T_lim/sf,rf=(A.rows.find(r=>r.T>=rt)?.F||A.rows[A.rows.length-1].F)*1.1;ds.push({label:'推奨T',data:[{x:rt,y:0},{x:rt,y:rf}],borderColor:'#639922',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[3,3]});}
607	  const opts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false},tooltip:{callbacks:{title:i=>`T = ${parseFloat(i[0].raw.x).toFixed(1)} Nm`,label:i=>`${i.dataset.label}: F = ${(parseFloat(i.raw.y)*1000).toFixed(0)} N`}}},scales:{x:{type:'linear',title:{display:true,text:'締め付けトルク T (Nm)',font:{size:10}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 F (kN)',font:{size:10}},ticks:{font:{size:9},callback:v=>v.toFixed(1)},grace:'5%'}}};
608	  mkC('cTF',{type:'line',data:{datasets:ds},options:opts});
