function doCalc(d,grK,Lg,mt,mw,nutK,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns){
  const b=BOLT[d],gr=GRADE[grK],nut=NUT_MAT[nutK],Eb=gr.E;
  const half=ang/2*Math.PI/180,beta=Math.atan(b.p/(Math.PI*b.d2)),rho=Math.atan(mt/Math.cos(half));
  let dw=b.dw,muw=mw;
  if(was==='flat')dw*=1.5;if(was==='spring')muw*=0.9;
  const bArea=(Math.PI/4)*(dw*dw-b.dh*b.dh),le=dep*d,nTh=le/b.p;
  const Fbrk=gr.Su*b.As/1000*tmp,Fstr=nut.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000,FbA=bA*bArea/1000,FbB=bB*bArea/1000,Fyld=gr.Sy*b.As/1000*tmp;
  const Flim=Math.min(Fbrk,Fstr,FbA,FbB);
  const failMode=[{mode:'ボルト破断',F:Fbrk},{mode:'山飛び（めねじ）',F:Fstr},{mode:'座面陥没 A面',F:FbA},{mode:'座面陥没 B面',F:FbB}].reduce((a,x)=>x.F<a.F?x:a).mode;
  const denom=(b.d2/2)*Math.tan(beta+rho)+(dw/2)*muw,Test=Flim*denom*1.35,step=Test/ns;
  const rows=[];
  for(let i=0;i<=ns+30;i++){
    const T=i*step,Fe=T/denom,sig=Fe*1000/b.As,J=Math.PI*Math.pow(b.d3/2,4)/2,tau=T*1000*(b.d3/2)/J*0.5,seq=Math.sqrt(sig*sig+3*tau*tau),plastic=seq>gr.Sy*tmp,Fact=plastic?Math.min(Fe,Fyld*1.01):Fe,util=seq/(gr.Su*tmp)*100;
    rows.push({T:+T.toFixed(3),F:+(Fact/1000).toFixed(4),sig:+sig.toFixed(1),tau:+tau.toFixed(1),seq:+seq.toFixed(1),util:+util.toFixed(1),plastic,over:Fact/1000>=Flim/1000*0.998});
    if(Fact/1000>Flim/1000*1.02)break;
  }
  return{rows,Flim,Fbrk,Fstr,FbA,FbB,Fyld,T_lim:rows.find(r=>r.over)?.T||null,T_yld:rows.find(r=>r.plastic)?.T||null,failMode,b,gr,nut,nutK,grK,d,dep,mu_t:mt,mu_w:muw,denom,dw,stiff:calcStiff(b,Eb,Lg,cmA,cmB,tA,tB),Eb,Lg,cmA,cmB,tA,tB,bA,bB};
}
function calc(){
  const ns=200,d=+gv('diam'),gr=gv('grade'),Lg=+gv('bolt_lg'),mt=+gv('mu_t'),mw=+gv('mu_w'),nut=gv('nut_mat'),dep=+gv('depth'),ang=+gv('thread_angle'),was=gv('washer'),tmp=+gv('temp'),bA=+gv('bearing_a'),bB=+gv('bearing_b'),cmA=gv('clamped_mat_a'),cmB=gv('clamped_mat_b'),tA=+gv('thick_a'),tB=+gv('thick_b');
  RES=doCalc(d,gr,Lg,mt,mw,nut,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns);
  const cmp=ge('cmp_on').checked;
  RES2=cmp?doCalc(+gv('diam2'),gv('grade2'),Lg,0.13,0.13,gv('nut_mat2'),+gv('depth2'),60,'none',tmp,bA,bB,gv('clamped_mat_a2'),gv('clamped_mat_b2'),+gv('thick_a2'),+gv('thick_b2'),ns):null;
  const sf=+gv('safety'),fext=+gv('f_ext');
  updateTop(RES,sf,cmp);
  if(curTab==='graph')drawGraphs(RES,RES2,sf);
  else if(curTab==='table')buildTable(RES);
  else if(curTab==='breakdown')buildBreakdown(RES,sf);
  else buildJoint(RES,sf,fext);
}
function updateTop(r,sf,cmp){
  ge('v-flim').innerHTML=(r.Flim/1000).toFixed(2)+'<span class="mc-u">kN</span>';
  ge('v-tlim').innerHTML=(r.T_lim?r.T_lim.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
  ge('v-tyld').innerHTML=(r.T_yld?r.T_yld.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
  ge('v-trec').innerHTML=(r.T_lim?(r.T_lim/sf).toFixed(1):'—')+'<span class="mc-u">Nm</span>';
  ge('v-trec-s').textContent='安全率 '+sf.toFixed(1);
  ge('v-phi').innerHTML=r.stiff.phi.toFixed(3);
  ge('mc0').className='mc '+(r.failMode!=='ボルト破断'?'danger':'ok');
  ge('bdg-mode').textContent=cmp?'比較モード':'単一解析';ge('bdg-mode').className='badge '+(cmp?'b-am':'b-bl');
  ge('bdg-fail').textContent=r.failMode==='ボルト破断'?'正常':'警告: '+r.failMode;ge('bdg-fail').className='badge '+(r.failMode==='ボルト破断'?'b-gn':'b-rd');
  const alerts=[];
  if(r.failMode==='山飛び（めねじ）')alerts.push('<div class="alert al-dn"><strong>警告: 山飛びリスク</strong>　めねじせん断破壊がボルト破断より先に発生します。ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。</div>');
  else if(r.failMode.includes('座面'))alerts.push(`<div class="alert al-dn"><strong>警告: 座面陥没リスク（${r.failMode}）</strong>　面圧超過がボルト破断より先に発生します。ワッシャー使用または許容面圧を見直してください。</div>`);
  if(r.stiff.phi>0.3)alerts.push(`<div class="alert al-wn">剛性比 Φ=${r.stiff.phi.toFixed(3)} — ボルト剛性が高く外部軸力がボルトに伝わりやすい状態です。</div>`);
  else if(r.stiff.phi<0.1)alerts.push(`<div class="alert al-ok">剛性比 Φ=${r.stiff.phi.toFixed(3)} — 部材剛性が高く外部軸力による軸力変動が小さい良好な継手です。</div>`);
  ge('alert-area').innerHTML=alerts.join('')||'<div class="alert al-ok">設計は良好です。ボルト破断が支配的で延性破壊が先行します。</div>';
}
function mkC(id,cfg){if(CH[id])CH[id].destroy();CH[id]=new Chart(ge(id).getContext('2d'),cfg)}
function drawGraphs(A,B,sf){
  const wc=A.failMode!=='ボルト破断',lc=wc?'#E24B4A':'#185FA5';
  const ds=[
    {label:'弾性域(A)',data:A.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
    {label:'塑性域(A)',data:A.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#EF9F27',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
    {label:'限界域(A)',data:A.rows.filter(r=>r.over).map(r=>({x:r.T,y:r.F})),borderColor:lc,backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,3]}
  ];
  if(B){ds.push({label:'弾性域(B)',data:B.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#D85A30',backgroundColor:'transparent',borderWidth:2,pointRadius:0,tension:0.2,borderDash:[4,2]});ds.push({label:'塑性域(B)',data:B.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F})),borderColor:'#993C1D',backgroundColor:'transparent',borderWidth:2,pointRadius:0,tension:0.2,borderDash:[4,2]});}
  if(A.T_lim){const rt=A.T_lim/sf,rf=(A.rows.find(r=>r.T>=rt)?.F||A.rows[A.rows.length-1].F)*1.1;ds.push({label:'推奨T',data:[{x:rt,y:0},{x:rt,y:rf}],borderColor:'#639922',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[3,3]});}
  const opts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false},tooltip:{callbacks:{title:i=>`T = ${parseFloat(i[0].raw.x).toFixed(1)} Nm`,label:i=>`${i.dataset.label}: F = ${(parseFloat(i.raw.y)*1000).toFixed(0)} N`}}},scales:{x:{type:'linear',title:{display:true,text:'締め付けトルク T (Nm)',font:{size:10}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 F (kN)',font:{size:10}},ticks:{font:{size:9},callback:v=>v.toFixed(1)},grace:'5%'}}};
  mkC('cTF',{type:'line',data:{datasets:ds},options:opts});
  ge('leg-tf').innerHTML=[{c:'#185FA5',l:'弾性域(A)'},{c:'#EF9F27',l:'塑性域(A)'},{c:lc,l:'限界(A)',d:true},{c:'#639922',l:'推奨T',d:true},...(B?[{c:'#D85A30',l:'弾性域(B)',d2:true},{c:'#993C1D',l:'塑性域(B)',d2:true}]:[])].map(i=>`<span class="li"><span class="ls" style="background:${i.d||i.d2?'transparent':i.c};${i.d?'border-top:2px dashed '+i.c:i.d2?'border-top:2px dotted '+i.c:''}"></span>${i.l}</span>`).join('');
  const stOpts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',title:{display:true,text:'T (Nm)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'応力 (MPa)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}};
  mkC('cST',{type:'line',data:{datasets:[{label:'σeq(A)',data:A.rows.map(r=>({x:r.T,y:r.seq})),borderColor:'#534AB7',backgroundColor:'transparent',borderWidth:2,pointRadius:0,tension:0.2},{label:'Sy',data:[{x:0,y:A.gr.Sy},{x:A.rows[A.rows.length-1].T,y:A.gr.Sy}],borderColor:'#EF9F27',backgroundColor:'transparent',borderWidth:1,pointRadius:0,borderDash:[5,3]},{label:'Su',data:[{x:0,y:A.gr.Su},{x:A.rows[A.rows.length-1].T,y:A.gr.Su}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:1,pointRadius:0,borderDash:[5,3]}]},options:stOpts});
  const bkL=['ボルト破断','山飛び','座面A','座面B'],bkV=[A.Fbrk/1000,A.Fstr/1000,A.FbA/1000,A.FbB/1000];
  mkC('cBK',{type:'bar',data:{labels:bkL,datasets:[{data:bkV,backgroundColor:bkV.map(v=>Math.abs(v-A.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false},tooltip:{callbacks:{label:i=>`${parseFloat(i.raw).toFixed(2)} kN`}}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9},callback:v=>v.toFixed(1)},grace:'5%'}}}});
}
function buildTable(r){
  const sk=Math.max(1,Math.floor(r.rows.length/80)),rows=r.rows.filter((_,i)=>i%sk===0||r.rows[i]?.over);
  ge('tbl-cnt').textContent=rows.length+'行';
  ge('tbl-body').innerHTML=rows.map(row=>{const cls=row.over?'lm':row.plastic?'pl':'',sb=row.over?'<span class="sb2 s-l">限界超</span>':row.plastic?'<span class="sb2 s-p">塑性域</span>':'<span class="sb2 s-e">弾性域</span>',jdg=row.over?'破損':row.util>90?'注意':row.util>70?'許容':'安全',jcl=row.over?'color:#A32D2D':row.util>70?'color:#854F0B':'color:#3B6D11';return `<tr class="${cls}"><td>${sb}</td><td>${row.T.toFixed(2)}</td><td>${(row.F*1000).toFixed(0)}</td><td>${row.sig.toFixed(0)}</td><td>${row.tau.toFixed(0)}</td><td>${row.seq.toFixed(0)}</td><td>${row.util.toFixed(1)}</td><td style="${jcl}">${jdg}</td></tr>`;}).join('');
}
function buildBreakdown(r,sf){
  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.nut.tau} MPa`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
  ['bd0','bd1','bd2','bd3'].forEach((id,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01;ge(id+'v').innerHTML=(Fs[i]/1000).toFixed(2)+'<span class="mc-u">kN</span>';ge(id+'s').textContent=descs[i];ge(id).className='mc '+(isL?'danger':'');});
  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc '+(r.failMode==='ボルト破断'?'ok':'danger');
  const bkL=['ボルト破断','山飛び','座面A','座面B'],lims=Fs.map(f=>f/1000),reqs=lims.map(v=>Math.min(v,r.Flim/1000)/sf);
  mkC('cMG',{type:'bar',data:{labels:bkL,datasets:[{label:'限界軸力',data:lims,backgroundColor:lims.map(v=>Math.abs(v-r.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0},{label:'要求(/S)',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
  const bkLL=['ボルト破断','山飛び（めねじ）','座面陥没 A面','座面陥没 B面'];
  ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01,mg=(Fs[i]/1000)/(r.Flim/1000/sf),tl=r.rows.find(row=>row.F>=(Fs[i]/1000)*0.998)?.T;return `<tr><td>${l}</td><td>${(Fs[i]/1000).toFixed(2)}</td><td>${tl?tl.toFixed(1):'—'}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;}).join('');
}
function buildJoint(r,sf,fext){
  const s=r.stiff;
  ge('jt-kb').textContent=(s.kb/1000).toFixed(0)+' kN/mm';ge('jt-kc').textContent=(s.kc/1000).toFixed(0)+' kN/mm';ge('jt-phi').textContent=s.phi.toFixed(4);
  const Fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf,half=Math.abs(fext)||Fi*0.5,Fext_range=Array.from({length:21},(_,i)=>(i-10)*half/10);
  mkC('cJT',{type:'line',data:{datasets:[{label:'ボルト軸力',data:Fext_range.map(fe=>({x:fe/1000,y:(Fi+s.phi*fe)/1000})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'残留締付力',data:Fext_range.map(fe=>({x:fe/1000,y:Math.max(0,(Fi-(1-s.phi)*fe)/1000)})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'初期Fi',data:[{x:Fext_range[0]/1000,y:Fi/1000},{x:Fext_range[20]/1000,y:Fi/1000}],borderColor:'#888',backgroundColor:'transparent',borderWidth:1,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',title:{display:true,text:'外部軸力 Fext (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
  const phiArr=Array.from({length:21},(_,i)=>+(i*0.05).toFixed(2));
  mkC('cPH',{type:'line',data:{datasets:[{label:'ボルト負担',data:phiArr.map(p=>({x:p,y:p})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'部材負担',data:phiArr.map(p=>({x:p,y:1-p})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'現在Φ',data:[{x:s.phi,y:0},{x:s.phi,y:1}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',min:0,max:1,title:{display:true,text:'剛性比 Φ',font:{size:9}},ticks:{font:{size:9}}},y:{min:0,max:1,title:{display:true,text:'外力分担割合',font:{size:9}},ticks:{font:{size:9}}}}}});
  ge('jt-tbl').innerHTML=[
    ['初期締付力 Fi',`${(Fi/1000).toFixed(2)} kN`,`推奨T ${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm 締付時`],
    ['ボルト剛性 kb',`${(s.kb/1000).toFixed(0)} kN/mm`,`E=${r.Eb} GPa, As=${r.b.As} mm², Lg=${r.Lg} mm`],
    ['被締結部材 A 剛性',`${(s.kca/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmA].name}, t=${r.tA} mm`],
    ['被締結部材 B 剛性',`${(s.kcb/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmB].name}, t=${r.tB} mm`],
    ['合成部材剛性 kc',`${(s.kc/1000).toFixed(0)} kN/mm`,'1/(1/kca + 1/kcb)'],
    ['剛性比 Φ',s.phi.toFixed(4),'Φ < 0.1 が推奨'],
    ['外部軸力のΔFb',`${(s.phi*(fext||0)/1000).toFixed(2)} kN`,`Fext = ${fext} N`],
    ['残留締付力',`${Math.max(0,(Fi-(1-s.phi)*(fext||0))/1000).toFixed(2)} kN`,'0以上を確認（開口防止）']
  ].map(([a,b,c])=>`<tr><td>${a}</td><td>${b}</td><td style="color:#888">${c}</td></tr>`).join('');
}
function switchTab(name){
  curTab=name;
  ['graph','table','breakdown','joint'].forEach(n=>{ge('tab-'+n).className='tab'+(n===name?' on':'');ge('pane-'+n).style.display=n===name?'':'none';});
  const sf=+gv('safety'),fext=+gv('f_ext');
  if(name==='graph')drawGraphs(RES,RES2,sf);
  else if(name==='table')buildTable(RES);
  else if(name==='breakdown')buildBreakdown(RES,sf);
  else buildJoint(RES,sf,fext);
}
function toggleCmp(){ge('caseb').style.display=ge('cmp_on').checked?'':'none';calc()}
function exportCSV(){if(!RES)return;let s='\uFEFFT(Nm),F(N),σ(MPa),τ(MPa),σeq(MPa),利用率(%),状態\n';RES.rows.forEach(r=>s+=`${r.T},${(r.F*1000).toFixed(0)},${r.sig},${r.tau},${r.seq},${r.util},${r.over?'限界超':r.plastic?'塑性域':'弾性域'}\n`);const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([s],{type:'text/csv;charset=utf-8'}));a.download=`bolt_M${RES.d}_${RES.grK}.csv`;a.click()}
function exportXLSX(){if(!RES||typeof XLSX==='undefined')return;const r=RES,sf=+gv('safety'),wb=XLSX.utils.book_new(),s=r.stiff,fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf;const sum=[['項目','値'],['ボルト径',`M${r.d}`],['強度区分',r.grK],['E(GPa)',r.Eb],['Lg(mm)',r.Lg],['μt',r.mu_t],['μw',r.mu_w],['めねじ材',r.nut.name],['ねじ込み',`${r.dep}D`],['被締結材A',CL_MAT[r.cmA].name],['tA(mm)',r.tA],['面圧A(MPa)',r.bA],['被締結材B',CL_MAT[r.cmB].name],['tB(mm)',r.tB],['面圧B(MPa)',r.bB],['安全率',sf],[' ',' '],['限界軸力(kN)',(r.Flim/1000).toFixed(3)],['ボルト破断(kN)',(r.Fbrk/1000).toFixed(3)],['山飛り(kN)',(r.Fstr/1000).toFixed(3)],['座面A(kN)',(r.FbA/1000).toFixed(3)],['座面B(kN)',(r.FbB/1000).toFixed(3)],['限界T(Nm)',r.T_lim?r.T_lim.toFixed(2):'—'],['降伏T(Nm)',r.T_yld?r.T_yld.toFixed(2):'—'],['推奨T(Nm)',r.T_lim?(r.T_lim/sf).toFixed(2):'—'],['破損モード',r.failMode],[' ',' '],['kb(N/mm)',s.kb.toFixed(0)],['kc(N/mm)',s.kc.toFixed(0)],['Φ',s.phi.toFixed(4)],['Fi(kN)',(fi/1000).toFixed(3)]];XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(sum),'解析サマリ');const data=[['T(Nm)','F(N)','σ(MPa)','τ(MPa)','σeq(MPa)','利用率(%)','状態']];RES.rows.forEach(row=>data.push([row.T,(row.F*1000).toFixed(0),row.sig,row.tau,row.seq,row.util,row.over?'限界超':row.plastic?'塑性域':'弾性域']));XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(data),'全生データ');XLSX.writeFile(wb,`bolt_M${r.d}_${r.grK}.xlsx`)}
function exportPDF(){
  if(!RES)return;
  const r=RES,sf=+gv('safety'),fext=+gv('f_ext'),s=r.stiff;
  const Fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf;
  const tfImg=ge('cTF')?ge('cTF').toDataURL('image/png'):null;
  const stImg=ge('cST')?ge('cST').toDataURL('image/png'):null;
  const now=new Date();
  const dateStr=`${now.getFullYear()}/${String(now.getMonth()+1).padStart(2,'0')}/${String(now.getDate()).padStart(2,'0')} ${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  let alertText='設計は良好です。ボルト破断が支配的で延性破壊が先行します。';
  let alertCls='rpt-alert-ok';
  if(r.failMode==='山飛び（めねじ）'){alertText='警告: 山飛びリスク — ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。';alertCls='rpt-alert-dn';}
  else if(r.failMode.includes('座面')){alertText=`警告: 座面陥没リスク（${r.failMode}）— ワッシャー使用または許容面圧を見直してください。`;alertCls='rpt-alert-dn';}
  const fmRows=[{n:'ボルト破断',F:r.Fbrk},{n:'山飛び（めねじ）',F:r.Fstr},{n:'座面陥没 A面',F:r.FbA},{n:'座面陥没 B面',F:r.FbB}];
  const cards=[
    {l:'限界軸力',     v:`${(r.Flim/1000).toFixed(2)} kN`},
    {l:'限界トルク',   v:`${r.T_lim?r.T_lim.toFixed(1):'—'} Nm`},
    {l:'降伏トルク',   v:`${r.T_yld?r.T_yld.toFixed(1):'—'} Nm`},
    {l:`推奨トルク (S=${sf.toFixed(1)})`,v:`${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm`},
    {l:'剛性比 Φ',     v:s.phi.toFixed(4)},
    {l:'支配的破損',   v:r.failMode}
  ];
  const cardRow=(arr)=>`<tr>${arr.map(c=>`<td><span class="cl">${c.l}</span><span class="cv">${c.v}</span></td>`).join('')}</tr>`;
  ge('pdf-report').innerHTML=`
  <div class="rpt-title">締め付けトルク解析レポート</div>
  <div class="rpt-sub">JIS B 1083 / Alexander式 準拠 &nbsp;|&nbsp; 生成日時: ${dateStr}</div>
  <div class="rpt-block">
    <div class="rpt-sec">解析条件</div>
    <table class="rpt-tbl"><colgroup><col class="c1"><col class="c2"></colgroup>
      <tr><td>ボルト径 / 強度区分</td><td>M${r.d} / ${r.grK} (Sy = ${r.gr.Sy} MPa, Su = ${r.gr.Su} MPa)</td></tr>
      <tr><td>有効長さ Lg</td><td>${r.Lg} mm</td></tr>
      <tr><td>摩擦係数 μt / μw</td><td>${r.mu_t.toFixed(2)} / ${r.mu_w.toFixed(2)}</td></tr>
      <tr><td>めねじ材 / ねじ込み深さ</td><td>${r.nut.name} / ${r.dep}D</td></tr>
      <tr><td>被締結材 A</td><td>${CL_MAT[r.cmA].name}, t = ${r.tA} mm, 許容面圧 ${r.bA} MPa</td></tr>
      <tr><td>被締結材 B</td><td>${CL_MAT[r.cmB].name}, t = ${r.tB} mm, 許容面圧 ${r.bB} MPa</td></tr>
      <tr><td>安全率 / 外部軸力</td><td>${sf.toFixed(1)} / ${fext} N</td></tr>
    </table>
  </div>
  <div class="rpt-block">
    <div class="rpt-sec">解析結果サマリ</div>
    <table class="rpt-cards">${cardRow(cards.slice(0,3))}${cardRow(cards.slice(3,6))}</table>
    <div class="rpt-alert ${alertCls}">${alertText}</div>

