0	<!DOCTYPE html>
1	<html lang="ja">
2	<head>
3	<meta charset="UTF-8">
4	<meta name="viewport" content="width=device-width, initial-scale=1.0">
5	<title>締め付けトルク判断支援ツール — JIS B 1083準拠</title>
6	<style>
7	*{box-sizing:border-box;margin:0;padding:0}
8	html,body{width:100%;overflow-x:hidden}
9	.app{display:flex;flex-direction:row;width:100%;min-height:800px;font-family:sans-serif;font-size:13px;color:#222;overflow:hidden}
10	.sb{width:290px;min-width:290px;max-width:290px;background:#fff;border-right:0.5px solid #ddd;display:flex;flex-direction:column;height:800px}
11	.sb-hd{padding:10px 13px 8px;border-bottom:0.5px solid #ddd;flex-shrink:0}
