774	  ['diam','grade','bolt_lg','mu_t','mu_w','thread_angle','washer','nut_mat','depth',
775	   'clamped_mat_a','thick_a','bearing_a','clamped_mat_b','thick_b','bearing_b',
776	   'temp','f_ext','safety'].forEach(k=>{const el=ge(k);if(el&&p[k]!==undefined)el.value=p[k];});
