548	const BOLT={3:{p:0.5,d2:2.675,d3:2.459,As:5.03,dw:5.5,dh:3.4},4:{p:0.7,d2:3.545,d3:3.242,As:8.78,dw:7.0,dh:4.5},5:{p:0.8,d2:4.480,d3:4.134,As:14.2,dw:8.8,dh:5.5},6:{p:1.0,d2:5.350,d3:4.917,As:20.1,dw:10.0,dh:6.6},8:{p:1.25,d2:7.188,d3:6.647,As:36.6,dw:13.0,dh:9.0},10:{p:1.5,d2:9.026,d3:8.376,As:58.0,dw:16.0,dh:11.0},12:{p:1.75,d2:10.863,d3:10.106,As:84.3,dw:18.0,dh:13.5},16:{p:2.0,d2:14.701,d3:13.835,As:157,dw:24.0,dh:17.5},20:{p:2.5,d2:18.376,d3:17.294,As:245,dw:30.0,dh:22.0},22:{p:2.5,d2:20.376,d3:19.294,As:303,dw:34.0,dh:24.0},24:{p:3.0,d2:22.051,d3:20.752,As:353,dw:36.0,dh:26.0},27:{p:3.0,d2:25.051,d3:23.752,As:459,dw:41.0,dh:30.0},30:{p:3.5,d2:27.727,d3:26.211,As:561,dw:46.0,dh:33.0},33:{p:3.5,d2:30.727,d3:29.211,As:694,dw:50.0,dh:36.0},36:{p:4.0,d2:33.402,d3:31.670,As:817,dw:55.0,dh:39.0},39:{p:4.0,d2:36.402,d3:34.670,As:976,dw:60.0,dh:42.0},42:{p:4.5,d2:39.077,d3:37.129,As:1121,dw:65.0,dh:45.0}};
549	const GRADE={'4.6':{Sy:240,Su:400,E:206,matNote:'低炭素鋼'},'4.8':{Sy:340,Su:420,E:206,matNote:'低炭素鋼'},'8.8':{Sy:660,Su:830,E:206,matNote:'中炭素鋼（焼入れ焼戻し）'},'10.9':{Sy:940,Su:1040,E:206,matNote:'合金鋼（焼入れ焼戻し）'},'12.9':{Sy:1100,Su:1220,E:206,matNote:'合金鋼（焼入れ焼戻し）'}};
550	const NUT_MAT={aluminum:{tau:80,bearing:60,name:'アルミ A6061',E:70},a5052:{tau:70,bearing:50,name:'アルミ A5052',E:70},steel:{tau:320,bearing:300,name:'鋼 SS400',E:206},s45c:{tau:420,bearing:380,name:'鋼 S45C',E:206},cast_iron:{tau:150,bearing:120,name:'鋳鉄 FC200',E:100},titanium:{tau:450,bearing:350,name:'チタン合金',E:114},brass:{tau:120,bearing:100,name:'真鍮 C3604',E:103},resin:{tau:40,bearing:30,name:'エンプラ',E:3}};
