557	function calcStiff(b,Eb,Lg,mA,mB,tA,tB){const kb=Eb*1000*b.As/Lg,Ac=(Math.PI/4)*(b.dw*b.dw-b.dh*b.dh),kca=CL_MAT[mA].E*1000*Ac/tA,kcb=CL_MAT[mB].E*1000*Ac/tB,kc=1/(1/kca+1/kcb);return{kb,kc,kca,kcb,phi:kb/(kb+kc)}}
558	function doCalc(d,grK,Lg,mt,mw,nutK,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns){
559	  const b=BOLT[d],gr=GRADE[grK],nut=NUT_MAT[nutK],Eb=gr.E;
560	  const half=ang/2*Math.PI/180,beta=Math.atan(b.p/(Math.PI*b.d2)),rho=Math.atan(mt/Math.cos(half));
561	  let dw=b.dw,muw=mw;
562	  if(was==='flat')dw*=1.5;if(was==='spring')muw*=0.9;
563	  const bArea=(Math.PI/4)*(dw*dw-b.dh*b.dh),le=dep*d,nTh=le/b.p;
564	  const Fbrk=gr.Su*b.As/1000*tmp,Fstr=nut.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000,FbA=bA*bArea/1000,FbB=bB*bArea/1000,Fyld=gr.Sy*b.As/1000*tmp;
565	  const Flim=Math.min(Fbrk,Fstr,FbA,FbB);
566	  const failMode=[{mode:'ボルト破断',F:Fbrk},{mode:'山飛び（めねじ）',F:Fstr},{mode:'座面陥没 A面',F:FbA},{mode:'座面陥没 B面',F:FbB}].reduce((a,x)=>x.F<a.F?x:a).mode;
567	  const denom=(b.d2/2)*Math.tan(beta+rho)+(dw/2)*muw,Test=Flim*denom*1.35,step=Test/ns;
568	  const rows=[];
569	  for(let i=0;i<=ns+30;i++){
570	    const T=i*step,Fe=T/denom,sig=Fe*1000/b.As,J=Math.PI*Math.pow(b.d3/2,4)/2,tau=T*1000*(b.d3/2)/J*0.5,seq=Math.sqrt(sig*sig+3*tau*tau),plastic=seq>gr.Sy*tmp,Fact=plastic?Math.min(Fe,Fyld*1.01):Fe,util=seq/(gr.Su*tmp)*100;
571	    rows.push({T:+T.toFixed(3),F:+(Fact/1000).toFixed(4),sig:+sig.toFixed(1),tau:+tau.toFixed(1),seq:+seq.toFixed(1),util:+util.toFixed(1),plastic,over:Fact/1000>=Flim/1000*0.998});
572	    if(Fact/1000>Flim/1000*1.02)break;
573	  }
574	  return{rows,Flim,Fbrk,Fstr,FbA,FbB,Fyld,T_lim:rows.find(r=>r.over)?.T||null,T_yld:rows.find(r=>r.plastic)?.T||null,failMode,b,gr,nut,nutK,grK,d,dep,mu_t:mt,mu_w:muw,denom,dw,stiff:calcStiff(b,Eb,Lg,cmA,cmB,tA,tB),Eb,Lg,cmA,cmB,tA,tB,bA,bB};
575	}
576	function calc(){
577	  const ns=200,d=+gv('diam'),gr=gv('grade'),Lg=+gv('bolt_lg'),mt=+gv('mu_t'),mw=+gv('mu_w'),nut=gv('nut_mat'),dep=+gv('depth'),ang=+gv('thread_angle'),was=gv('washer'),tmp=+gv('temp'),bA=+gv('bearing_a'),bB=+gv('bearing_b'),cmA=gv('clamped_mat_a'),cmB=gv('clamped_mat_b'),tA=+gv('thick_a'),tB=+gv('thick_b');
