const NUT_MAT={aluminum:{tau:80,bearing:60,name:'アルミ A6061',E:70},a5052:{tau:70,bearing:50,name:'アルミ A5052',E:70},steel:{tau:320,bearing:300,name:'鋼 SS400',E:206},s45c:{tau:420,bearing:380,name:'鋼 S45C',E:206},cast_iron:{tau:150,bearing:120,name:'鋳鉄 FC200',E:100},titanium:{tau:450,bearing:350,name:'チタン合金',E:114},brass:{tau:120,bearing:100,name:'真鍮 C3604',E:103},resin:{tau:40,bearing:30,name:'エンプラ',E:3}};
const CL_MAT={aluminum:{E:70,name:'アルミ合金',bearing:60},steel:{E:206,name:'鋼',bearing:300},cast_iron:{E:100,name:'鋳鉄',bearing:120},titanium:{E:114,name:'チタン合金',bearing:350},brass:{E:103,name:'真鍮',bearing:100},resin:{E:3,name:'エンプラ',bearing:30},cfrp:{E:70,name:'CFRP',bearing:150}};
