654	function calc(){
655	  const ns=200,d=+gv('diam'),gr=gv('grade'),Lg=+gv('bolt_lg'),mt=+gv('mu_t'),mw=+gv('mu_w'),nut=gv('nut_mat'),dep=+gv('depth'),ang=+gv('thread_angle'),was=gv('washer'),tmp=+gv('temp'),bA=+gv('bearing_a'),bB=+gv('bearing_b'),cmA=gv('clamped_mat_a'),cmB=gv('clamped_mat_b'),tA=+gv('thick_a'),tB=+gv('thick_b');
656	  let bOvr=null,grOvr=null;
657	  if(boltMode==='inch'){const uk=gv('diam_unc');bOvr=BOLT_UNC[uk];grOvr=GRADE_ASTM[gv('grade_astm')];}
658	  RES=doCalc(d,gr,Lg,mt,mw,nut,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns,bOvr,grOvr);
659	  const cmp=ge('cmp_on').checked;
660	  RES2=cmp?doCalc(+gv('diam2'),gv('grade2'),Lg,0.13,0.13,gv('nut_mat2'),+gv('depth2'),60,'none',tmp,bA,bB,gv('clamped_mat_a2'),gv('clamped_mat_b2'),+gv('thick_a2'),+gv('thick_b2'),ns):null;
661	  const sf=+gv('safety'),fext=+gv('f_ext');
662	  updateTop(RES,sf,cmp);
663	  if(curTab==='graph')drawGraphs(RES,RES2,sf);
664	  else if(curTab==='table')buildTable(RES);
665	  else if(curTab==='breakdown')buildBreakdown(RES,sf);
666	  else if(curTab==='joint')buildJoint(RES,sf,fext);
667	  else if(curTab==='fatigue')buildFatigue(RES,sf);
668	}
669	function updateTop(r,sf,cmp){
670	  ge('v-flim').innerHTML=(r.Flim/1000).toFixed(2)+'<span class="mc-u">kN</span>';
671	  ge('v-tlim').innerHTML=(r.T_lim?r.T_lim.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
672	  ge('v-tyld').innerHTML=(r.T_yld?r.T_yld.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
673	  ge('v-trec').innerHTML=(r.T_lim?(r.T_lim/sf).toFixed(1):'—')+'<span class="mc-u">Nm</span>';
674	  ge('v-trec-s').textContent='安全率 '+sf.toFixed(1);
675	  ge('v-phi').innerHTML=r.stiff.phi.toFixed(3);
676	  ge('mc0').className='mc '+(r.failMode!=='ボルト破断'?'danger':'ok');
677	  ge('bdg-mode').textContent=cmp?'比較モード':'単一解析';ge('bdg-mode').className='badge '+(cmp?'b-am':'b-bl');
678	  ge('bdg-fail').textContent=r.failMode==='ボルト破断'?'正常':'警告: '+r.failMode;ge('bdg-fail').className='badge '+(r.failMode==='ボルト破断'?'b-gn':'b-rd');
679	  const alerts=[];
680	  if(r.failMode==='山飛び（めねじ）')alerts.push('<div class="alert al-dn"><strong>警告: 山飛びリスク</strong>　めねじせん断破壊がボルト破断より先に発生します。ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。</div>');
681	  else if(r.failMode.includes('座面'))alerts.push(`<div class="alert al-dn"><strong>警告: 座面陥没リスク（${r.failMode}）</strong>　面圧超過がボルト破断より先に発生します。ワッシャー使用または許容面圧を見直してください。</div>`);
682	  if(r.stiff.phi>0.3)alerts.push(`<div class="alert al-wn">剛性比 Φ=${r.stiff.phi.toFixed(3)} — ボルト剛性が高く外部軸力がボルトに伝わりやすい状態です。</div>`);
683	  else if(r.stiff.phi<0.1)alerts.push(`<div class="alert al-ok">剛性比 Φ=${r.stiff.phi.toFixed(3)} — 部材剛性が高く外部軸力による軸力変動が小さい良好な継手です。</div>`);
684	  ge('alert-area').innerHTML=alerts.join('')||'<div class="alert al-ok">設計は良好です。ボルト破断が支配的で延性破壊が先行します。</div>';
685	}
686	function mkC(id,cfg){if(CH[id])CH[id].destroy();CH[id]=new Chart(ge(id).getContext('2d'),cfg)}
687	function drawGraphs(A,B,sf){
