import re

with open('/mnt/c/Users/makoto/Downloads/bolt_torque_simulator.html', 'r', encoding='utf-8') as f:
    content = f.read()

# Extract the script content
script_match = re.search(r'<script>(.*?)</script>', content, re.DOTALL)
if script_match:
    js = script_match.group(1)
    lines = js.split('\n')
    print(f'Script lines: {len(lines)}')

    # Check for any afterFit outside of Chart.register
    for i, line in enumerate(lines, 1):
        if 'afterFit' in line:
            print(f'Line {i+618}: {line[:100]}')

    # Check for duplicate const declarations
    decls = {}
    for i, line in enumerate(lines, 1):
        for m in re.finditer(r'\bconst\s+(\w+)\s*=', line):
            name = m.group(1)
            if name in decls:
                print(f'DUPLICATE const {name}: lines {decls[name]} and {i+618}')
            else:
                decls[name] = i+618

    for i, line in enumerate(lines, 1):
        for m in re.finditer(r'\blet\s+(\w+)', line):
            name = m.group(1)
            if name in decls:
                print(f'CONFLICT let {name} with existing const: line {i+618}')

print('Check done')
"

